use serde::Deserialize;

#[derive(Deserialize, Debug)]
struct Event<'a> {
    id: u64,
    name: &'a str,       // borrows from the deserialized input
    tags: Vec<&'a str>,  // each tag borrows from the input
}

fn main() {
    let json = r#"{"id":1,"name":"click","tags":["ui","mouse"]}"#;
    // from_str: input is &str, so we can borrow from it
    let event: Event = serde_json::from_str(json).unwrap();
    println!("{:?}", event);
    println!("name: {}, tags: {:?}", event.name, event.tags);
    // event.name points directly into `json` — no String allocation
}

