use serde::Deserialize;
use std::borrow::Cow;

// Cow<'a, str> borrows when possible, owns when necessary
#[derive(Deserialize, Debug)]
struct Packet<'a> {
    src: Cow<'a, str>,
    dst: Cow<'a, str>,
}

// Option A: let the caller own the input
fn parse_packet(json: &str) -> Packet<'_> {
    serde_json::from_str(json).unwrap()
}

// Option B: return fully owned struct, give up zero-copy
#[derive(Deserialize, Debug)]
struct OwnedPacket {
    src: String,
    dst: String,
}

fn parse_owned_packet(json: &str) -> OwnedPacket {
    serde_json::from_str(json).unwrap()
}

fn main() {
    // Option A: caller owns the input string, passes a borrow
    let json = r#"{"src":"10.0.0.1","dst":"10.0.0.2"}"#.to_owned();
    let p = parse_packet(&json);
    println!("{} -> {}", p.src, p.dst);

    // Option B: function owns and deserializes, returns owned
    let p2 = parse_owned_packet(&json);
    println!("{} -> {}", p2.src, p2.dst);
}

