use serde::Deserialize;
use std::fs;

// For file reading, you must either:
// A) Read the whole file into memory first, then zero-copy from the buffer
#[derive(Deserialize, Debug)]
struct RecordBorrowed<'a> {
    id: u64,
    name: &'a str,
}

// B) Use owned types — DeserializeOwned works with from_reader
#[derive(Deserialize, Debug)]
struct RecordOwned {
    id: u64,
    name: String,
}

fn main() {
    let json = r#"{"id":1,"name":"Alice"}"#;

    // Option A: load into memory, then zero-copy deserialize
    let buf: String = json.to_owned();
    let record: RecordBorrowed = serde_json::from_str(&buf).unwrap();
    println!("zero-copy: {:?}", record);

    // For from_reader you need owned fields:
    // let file = File::open("data.json").unwrap();
    // let record: RecordOwned = serde_json::from_reader(BufReader::new(file)).unwrap();

    let record_owned: RecordOwned = serde_json::from_str(json).unwrap();
    println!("owned: {:?}", record_owned);
}

