use serde::Deserialize;
use std::borrow::Cow;

#[derive(Deserialize, Debug)]
struct Message<'a> {
    // id is a simple identifier — likely no escapes, zero-copy
    #[serde(borrow)]
    id: &'a str,
    // body may contain escapes — Cow borrows when possible, owns when not
    body: Cow<'a, str>,
}

fn main() {
    // Simple body: zero-copy for both fields
    let json1 = r#"{"id":"abc","body":"hello world"}"#;
    let msg1: Message = serde_json::from_str(json1).unwrap();
    println!("msg1: {:?} (body owned: {})", msg1, matches!(msg1.body, Cow::Owned(_)));

    // Body with escape: id still zero-copy, body allocates
    let json2 = r#"{"id":"def","body":"hello\nworld"}"#;
    let msg2: Message = serde_json::from_str(json2).unwrap();
    println!("msg2: {:?} (body owned: {})", msg2, matches!(msg2.body, Cow::Owned(_)));
}

