use serde::de::{self, Deserializer, MapAccess, Visitor};
use serde::Deserialize;
use std::fmt;

#[derive(Debug)]
struct BinaryRecord<'a> {
    name: &'a str,
    data: &'a [u8],
}

impl<'de: 'a, 'a> Deserialize<'de> for BinaryRecord<'a> {
    fn deserialize<D: Deserializer<'de>>(deserializer: D) -> Result<Self, D::Error> {
        struct BinaryRecordVisitor;

        impl<'de> Visitor<'de> for BinaryRecordVisitor {
            type Value = BinaryRecord<'de>;

            fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
                write!(f, "a BinaryRecord")
            }

            fn visit_map<A: MapAccess<'de>>(self, mut map: A) -> Result<BinaryRecord<'de>, A::Error> {
                let mut name: Option<&'de str> = None;
                let mut data: Option<&'de [u8]> = None;
                while let Some(key) = map.next_key::<&str>()? {
                    match key {
                        "name" => name = Some(map.next_value()?),
                        "data" => data = Some(map.next_value()?),
                        _ => { map.next_value::<de::IgnoredAny>()?; }
                    }
                }
                Ok(BinaryRecord {
                    name: name.ok_or_else(|| de::Error::missing_field("name"))?,
                    data: data.ok_or_else(|| de::Error::missing_field("data"))?,
                })
            }
        }

        deserializer.deserialize_map(BinaryRecordVisitor)
    }
}

fn main() {
    // serde_json doesn't support &[u8] borrowing from JSON, but bincode does
    // Using derive for the common case:
    #[derive(Deserialize, Debug)]
    struct BorrowedRecord<'de> {
        #[serde(borrow)]
        name: &'de str,
        data: Vec<u8>,  // owned bytes — zero-copy &[u8] requires a binary format
    }

    let json = r#"{"name":"test","data":[1,2,3]}"#;
    let r: BorrowedRecord = serde_json::from_str(json).unwrap();
    println!("{:?}", r);
}
